// declarationFile is the parsed shape of capabilities.yaml. It is
// intentionally narrower than adapter.AdapterManifest so the file
// stays a per-adapter declaration and not an arbitrary manifest
// override.
type declarationFile struct {
	Name            string                            `yaml:"name"`
	Version         string                            `yaml:"version"`
	ContractVersion string                            `yaml:"contract_version"`
	ReservedPrefix  string                            `yaml:"reserved_prefix"`
	ConceptKinds    map[string]conceptKindDeclaration `yaml:"concept_kinds"`
}

type conceptKindDeclaration struct {
	Status capmatrix.CapabilityStatus `yaml:"status"`
	Note   string                     `yaml:"note,omitempty"`
}

// conceptKinds is the in-code mirror of capabilities.yaml. The unit
// test asserts the two are kept in sync; if you add a kind here,
// add it there (and vice versa).
//
// Cursor declares one kind unsupported: plugin-reference (no project plugin
// registry). skill is supported via the shared .agents/skills tree; command via
// the file-leaf .cursor/commands tree. See capabilities.yaml notes and
// docs/adapters/cursor.md for the rationale.
var conceptKinds = map[ir.Kind]capmatrix.CapabilityStatus{
	ir.KindAgentsMD:        capmatrix.Supported,
	ir.KindRule:            capmatrix.Supported,
	ir.KindMCPServerEntry:  capmatrix.Supported,
	ir.KindSkill:           capmatrix.Supported,
	ir.KindCommand:         capmatrix.Supported,
	ir.KindPluginReference: capmatrix.Unsupported,
}

// capabilitiesForWire returns the adapterkit.Capabilities the adapter
// echoes in its initialize response. WriteToolOwned is true because
// the cursor adapter emits write_tool_owned ops for .cursor/mcp.json
// and AGENTS.md.
//
// The set is scope-aware. At user scope, rule and agents-md are declared
// UNSUPPORTED: Cursor has no file-addressable user-global home for either
// (User Rules are app-settings/cloud; there is no global AGENTS.md), so
// dispatchNode skips them. Declaring them unsupported — rather than leaving
// them "supported" while emitting nothing — is load-bearing: the runtime's
// capability-lied gate (runtime.go) fails any session that declares a kind
// supported, receives an in-target node of that kind, and emits zero
// non-warning ops. A user-scope manifest targeting Cursor with only a rule
// (no MCP entry) hits exactly that case, so the declaration must match the
// emit reality. See dispatchNode + plan docs/plans/2026-06-30-001.
func capabilitiesForWire(scope string) adapterkit.Capabilities {
	builder := adapterkit.NewCapabilities().WithWriteToolOwned(true)
	for kind, status := range conceptKinds {
		if scope == scopeUser && (kind == ir.KindRule || kind == ir.KindAgentsMD) {
			builder.Unsupported(string(kind))
			continue
		}
		switch status {
		case capmatrix.Supported:
			builder.Supports(string(kind))
		case capmatrix.Partial:
			builder.Partial(string(kind))
		case capmatrix.Unsupported:
			builder.Unsupported(string(kind))
		}
	}
	return builder.Build()
}

// declaredOutputs returns the list the adapter advertises in its
// initialize response. The runtime path-safety gate
// (internal/adapter/runtime.go pathInDeclaredOutputs) accepts an
// emitted op only when its path falls inside one of these declared
// outputs.
//
// The set is scope-aware. At user scope only .cursor/mcp.json is declared:
// it is the sole file-addressable user-global Cursor config (~/.cursor/mcp.json),
// the sidecar is suppressed (the global mcp.json is Cursor's own file), and
// rules / AGENTS.md have no user-global home so they are neither declared nor
// emitted (see emit.go dispatchNode and coverage.nonNativeAtUser). Paths come
// from resolvePathSet so declared and emitted paths never drift. See plan
// docs/plans/2026-06-30-001.
func declaredOutputs(scope string) []adapterkit.DeclaredOutput {
	mcpPointer := "/mcpServers"
	paths := resolvePathSet(scope)
	outputs := []adapterkit.DeclaredOutput{
		{Path: paths.mcpJSON, Mode: adapterkit.OutputModeToolOwnedEntry, JSONPointer: &mcpPointer},
		// .agents/skills is the shared cross-tool skills tree (cursor, codex, pi,
		// antigravity co-own it). shared-subdir → the engine manages only the
		// agent-sync-<id> leaf dirs, never the parent, so foreign and
		// sibling-adapter skills survive a sync (ADV-1). Declared at both scopes:
		// the relative path resolves to ~/.agents/skills at user scope, which
		// Cursor also reads.
		{Path: skillsParent, Mode: adapterkit.OutputModeSharedSubdir},
		// .cursor/commands is a flat shared dir Cursor reads at the project root
		// and (as ~/.cursor/commands) at user scope. file-leaf → agent-sync owns
		// only the individual <id>.md files it emits, never the dir or foreign
		// files. Declared at both scopes (scope-invariant relative path).
		{Path: commandsParent, Mode: adapterkit.OutputModeFileLeaf},
	}
	if scope == scopeUser {
		return outputs
	}
	agentsMDSection := "agent-sync"
	outputs = append(outputs,
		adapterkit.DeclaredOutput{Path: ".cursor/rules/agent-sync", Mode: adapterkit.OutputModeOwnedSubdir},
		adapterkit.DeclaredOutput{Path: agentsMDPath, Mode: adapterkit.OutputModeToolOwnedEntry, SectionID: &agentsMDSection},
		// The strict-JSON sidecar marker (.agent-sync-managed) is written
		// next to .cursor/mcp.json under .cursor/. Declared by exact
		// path (owned-subdir mode authorizes the path; the write_file
		// op writes it) rather than over-broadly authorizing .cursor/.
		adapterkit.DeclaredOutput{Path: paths.sidecar, Mode: adapterkit.OutputModeOwnedSubdir},
	)
	return outputs
}

// parseCapabilitiesYAML decodes the embedded YAML. Used by the parity
// test and by callers that want the human-readable note bodies.
func parseCapabilitiesYAML(src []byte) (declarationFile, error) {
	var d declarationFile
	if err := yaml.UnmarshalWithOptions(
		src,
		&d,
		yaml.DisallowUnknownField(),
		yaml.AllowFieldPrefixes("x-"),
	); err != nil {
		return declarationFile{}, fmt.Errorf("cursor: parse capabilities.yaml: %s", yaml.FormatError(err, false, true))
	}
	return d, nil
}

// loadDeclaration parses the embedded capabilities.yaml and returns
// the result.
func loadDeclaration() (declarationFile, error) {
	return parseCapabilitiesYAML(capabilitiesYAML)
