		if _, err := fmt.Fprintf(w, "  source: %s\n", sc.Source); err != nil {
			return err
		}
		for _, t := range sc.Targets {
			state := "untracked"
			if t.Tracked {
				state = fmt.Sprintf("%d managed file(s)", t.Managed)
			}
			if _, err := fmt.Fprintf(w, "  target %s: %s\n", t.Target, state); err != nil {
