func renderStatusText(cmd *cobra.Command, rep statusReport) error {
	w := cmd.OutOrStdout()
	if rep.WatchFailed {
		if _, err := fmt.Fprintln(w, "WARNING: the last watch-mode sync failed (see .agent-sync/state/last-watch.failed)"); err != nil {
			return err
		}
