// String returns the lowercase label used in status output and warnings.
func (l Level) String() string {
	switch l {
	case LevelUser:
		return "user"
	case LevelProject:
		return "project"
	case LevelDirectory:
		return "directory"
	default:
		return "unknown"
	}
}

